#[derive(Debug, PartialEq)]
pub enum Command {
    [[SLOT say_variant]]
    [[SLOT move_variant]]
    Quit,
}

impl Command {
    pub fn describe(&self) -> String {
        match self {
            [[SLOT say_arm]],
            [[SLOT move_arm]],
            Command::Quit => String::from("Quit"),
        }
    }
}

fn main() {
    let cmd = Command::Say(String::from("hello"));
    println!("{}", cmd.describe());
}
